#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Function to solve the problem
ll solve(const vector<ll>& nums) {
    int n = nums.size();
    if (n < 3) {
        return 0;
    }

    // The maximum number of special indices is related to the structure of peaks.
    // We want to create a sequence like: Up, Peak, Down, Up, Peak, Down, ...
    // The maximum number of peaks we can create is floor((n-1)/2).
    // Let k be the number of peaks we aim for. The maximum k is floor((n-1)/2).

    // This problem can be modeled as finding the minimum cost to satisfy a set of constraints.
    // Since we only increase values, the cost is monotonic with the target values.

    // The maximum possible number of peaks is ceil((n-2)/2) if we consider indices 1 to n-2.
    // Indices are 0, 1, ..., n-1. Special indices i must satisfy 0 < i < n-1.
    // Possible special indices: 1, 2, ..., n-2. Total n-2 candidates.
    // To have a peak at i, we need nums[i] > nums[i-1] and nums[i] > nums[i+1].
    // If we have peaks at i and j (i < j), the minimum separation is 2 (e.g., i, i+2).
    // The maximum number of non-overlapping peaks we can create is achieved by placing them at 1, 3, 5, ...
    // The last possible peak is at n-2.
    // Number of peaks = floor((n-2 - 1) / 2) + 1 = floor((n-3)/2) + 1.
    // Example n=5, indices 1, 2, 3. Max peaks at 1, 3. Count = 2. floor(2/2)+1 = 2.
    // Example n=4, indices 1, 2. Max peaks at 1. Count = 1. floor(1/2)+1 = 1.
    // Example n=3, index 1. Max peaks at 1. Count = 1. floor(0/2)+1 = 1.

    int max_k = (n - 3) / 2 + 1; // Maximum achievable number of peaks

    // We need to find the minimum cost to achieve *at least* max_k peaks, but since we aim for max_k,
    // we focus on the structure that achieves max_k with minimum cost.

    // The greedy approach: To minimize cost, we should aim for the smallest required height for the peaks.
    // If we target peaks at positions 1, 3, 5, ..., 2*max_k - 1.

    // Let's re-evaluate the structure. We want to create a sequence of local maxima.
    // If we set nums[2i+1] to be a peak, we need:
    // nums[2i+1] > nums[2i] and nums[2i+1] > nums[2i+2].

    // Since increasing one value might help satisfy constraints for multiple potential peaks,
    // this suggests a dynamic programming or a careful greedy approach based on required heights.

    // Due to the nature of the constraints (only increase), we should try to satisfy the constraints
    // for the maximum possible set of peaks, $K = \lfloor (n-1)/2 \rfloor$ if we could place them anywhere,
    // but here the minimum separation is 2 if they are not adjacent to the edges.

    // Let's simplify the goal: Achieve the maximum number of peaks $K_{max}$ at minimum cost.
    // $K_{max} = \lfloor (n-2)/2 \rfloor$ is wrong.
    // $n=3$, indices {1}. Max peaks = 1. $\lfloor (3-1)/2 \rfloor = 1$.
    // $n=4$, indices {1, 2}. Max peaks = 1 (at 1 or 2). $\lfloor (4-1)/2 \rfloor = 1$.
    // $n=5$, indices {1, 2, 3}. Max peaks = 2 (at 1, 3). $\lfloor (5-1)/2 \rfloor = 2$.
    // $n=6$, indices {1, 2, 3, 4}. Max peaks = 2 (at 1, 3 or 2, 4). $\lfloor (6-1)/2 \rfloor = 2$.
    // $K_{max} = \lfloor (n-1)/2 \rfloor$. This seems correct for the maximum *possible* count if we ignore intermediate constraints.

    // Let's use the structure $P_1, P_2, \dots, P_{K_{max}}$ where $P_i$ are the peak indices.
    // To minimize cost, we should choose the indices $i$ greedily such that the required height is minimal.
    // The set of indices $\{1, 3, 5, \dots, 2K_{max}-1\}$ is the standard greedy choice.

    // Target peaks at $i = 1, 3, 5, \dots$
    vector<int> peak_indices;
    for (int i = 1; i <= n - 2; i += 2) {
        peak_indices.push_back(i);
    }
    int K = peak_indices.size(); // K = floor((n-1)/2)

    // We must satisfy:
    // For each $i \in peak\_indices$:
    // $nums'[i] > nums'[i-1]$
    // $nums'[i] > nums'[i+1]$

    // Since we only increase, and the targets are coupled (changing nums[i] affects neighbors),
    // we process the required peaks sequentially and greedily satisfy the constraints for the current peak,
    // assuming previous modifications are final.

    vector<ll> current_nums = vector<ll>(nums.begin(), nums.end());
    ll total_cost = 0;

    for (int i : peak_indices) {
        ll required_left = current_nums[i - 1] + 1;
        ll required_right = current_nums[i + 1] + 1;
        ll required_peak = max(required_left, required_right);

        ll current_peak = current_nums[i];

        if (current_peak < required_peak) {
            ll needed_increase = required_peak - current_peak;
            total_cost += needed_increase;
            current_nums[i] += needed_increase;
        }

        // Note: If we increase current_nums[i], it might satisfy constraints for neighbors' peaks,
        // or it might increase the requirement for its neighbors if they were peaks.
        // Since we only chose peaks at i = 1, 3, 5, ..., their neighbors are at even indices (0, 2, 4, ...).
        // The neighbors are either edges (0, n-1) or non-peak indices.
        // If $i-1$ or $i+1$ were potential peaks, they would be at indices $2j$, which are not in our chosen set $\{1, 3, 5, \dots\}$.
        // The set of neighbors of our chosen peaks are either edges or non-peak indices, so the greedy local satisfaction works.
    }

    return total_cost;
}
