#include <vector>
#include <algorithm>
#include <cmath>
#include <iostream>

using namespace std;

/**
 * @brief 解决最大化特殊下标数量并最小化操作数的最小操作数问题。
 * 
 * 特殊下标 i 满足: 0 < i < n - 1 且 nums[i] > nums[i-1] 且 nums[i] > nums[i+1]。
 * 操作是选择任意 i 增加 nums[i] 的值。
 * 
 * 目标是：
 * 1. 最大化特殊下标的数量 (MaxPeaks)。
 * 2. 在 MaxPeaks 下，最小化总操作数 (MinCost)。
 * 
 * 关键观察:
 * 1. 要使 nums[i] 成为峰值，我们需要 nums[i] > nums[i-1] 且 nums[i] > nums[i+1]。
 * 2. 我们只能增加元素的值。这使得增加峰值更容易实现，但代价是增加操作数。
 * 3. 增加 nums[i] 可能会影响到 i-1 和 i+1 是否是峰值，以及 i-2 和 i+2 是否是峰值。
 * 4. 如果我们确定了哪些下标 $i$ 将成为峰值，那么对于每个 $i$，我们需要的最小 $nums[i]$ 是 $\max(nums[i-1] + 1, nums[i+1] + 1)$。
 * 5. 由于我们只能增加值，如果我们增加 $nums[i]$，它可能会帮助 $i-1$ 和 $i+1$ 成为峰值，但这通常需要 $nums[i-2]$ 或 $nums[i+2]$ 的值也相应增大，导致依赖性很强。
 * 
 * 考虑最大化峰值数量：
 * 两个相邻的下标 $i$ 和 $i+1$ 不能同时是峰值。
 * 如果 $i$ 是峰值，则 $nums[i] > nums[i-1]$ 且 $nums[i] > nums[i+1]$。
 * 如果 $i+1$ 是峰值，则 $nums[i+1] > nums[i]$ 且 $nums[i+1] > nums[i+2]$。
 * 这两个条件 $nums[i] > nums[i+1]$ 和 $nums[i+1] > nums[i]$ 是矛盾的。
 * 因此，最大化峰值数量 $\text{MaxPeaks}$ 的限制是：
 * $\text{MaxPeaks} \le \lceil \frac{n-2}{2} \rceil$. (因为我们选择的是 $i$ 使得 $0 < i < n-1$)
 * 最多可以选取所有奇数或所有偶数（除了边界）作为峰值。
 * 
 * 贪心策略：
 * 我们可以尝试构造一个最优解，即选择一个最大数量的、不相邻的下标作为峰值，然后计算达到这个状态所需的最小操作数。
 * 
 * 考虑两个不相邻的下标 $i$ 和 $j$ ($|i-j| \ge 2$) 作为峰值。
 * 要使 $i$ 是峰值，需要 $nums'[i] > nums'[i-1]$ 和 $nums'[i] > nums'[i+1]$。
 * 要使 $j$ 是峰值，需要 $nums'[j] > nums'[j-1]$ 和 $nums'[j] > nums'[j+1]$。
 * 
 * 由于我们只能增加值，一个关键的洞察是：如果两个峰值 $i$ 和 $j$ 的邻居不重叠（即 $|i-j| \ge 3$），那么它们的影响是独立的。
 * 如果它们相邻（即 $|i-j|=2$，例如 $i$ 和 $i+2$），那么它们共享一个邻居 $i+1$。
 * 
 * 这个问题可以通过动态规划来解决，目标是选择一个最大独立集（在特定图上），然后计算最小成本。
 * 
 * 设 $N$ 是数组长度。我们关心下标 $i \in [1, N-2]$。
 * 考虑一个更强的约束：如果我们确定了 $S$ 是峰值的集合，我们必须最小化 $\sum_{i \in S} \max(0, \text{needed}(i) - nums[i])$，同时满足所有邻居的约束。
 * 
 * 由于操作是可累加的，一个简单的贪心或DP应该有效。
 * 
 * 尝试 DP:
 * $DP[i]$: 考虑前 $i+1$ 个元素 ($nums[0] \dots nums[i]$)，所能达到的最大峰值数量和最小代价。
 * 
 * 状态需要携带信息：$nums[i]$ 的最终值，因为它影响到 $i+1$ 和 $i+2$ 的峰值条件。
 * 这是一个非常复杂的DP，因为最终值是可变的，且变化是相对的。
 * 
 * **回归到最大化峰值数量的结构限制：**
 * MaxPeaks $\le \lceil \frac{N-2}{2} \rceil$.
 * 我们只需找到一个达到这个最大数量的峰值集合 $S$，使得 $\text{Cost}(S)$ 最小。
 * 
 * 我们可以枚举所有可能的最大峰值集合 $S$ 的结构（例如，所有奇数下标，或所有偶数下标），然后计算成本。
 * 
 * 结构 1: $S_1 = \{1, 3, 5, \dots\}$ (所有奇数下标 $\le N-2$)
 * 结构 2: $S_2 = \{2, 4, 6, \dots\}$ (所有偶数下标 $\le N-2$)
 * 
 * 实际上，最优解的峰值集合 $S$ 必须是独立集（不相邻）。因此，它一定是某种交错的结构。
 * 
 * 让我们假设我们已经确定了目标峰值集合 $S$。
 * 对于每个 $i \in S$，我们必须有 $nums'[i] > nums'[i-1]$ 且 $nums'[i] > nums'[i+1]$。
 * 此外，对于 $j \notin S$ 且 $1 \le j \le N-2$，如果 $j$ 成为峰值，我们不计入 $S$ 的数量，但我们必须保证我们的成本最小化，这意味着我们不应该让 $j$ 成为峰值，除非它不影响 $S$ 的成本。
 * 
 * 关键假设（来自类似问题的观察）：为了最小化成本，我们应该只关注那些“必须”变成峰值的元素 $i \in S$，并且不让其他元素 $j \notin S$ 变成峰值，除非为了满足 $i \in S$ 的条件所必需。
 * 
 * 如果我们只考虑 $S$ 上的元素，那么我们只需要最小化 $\sum_{i \in S} \text{Cost}_i$.
 * 对于 $i \in S$，我们需要 $nums'[i] \ge \max(nums'[i-1], nums'[i+1]) + 1$.
 * 
 * 由于我们只增加值，我们应该最小化所有 $nums'[i]$ 的值。
 * $nums'[i] = \max(nums[i], \text{required\_by\_neighbors})$.
 * 
 * 如果我们固定 $S$ (一个不相邻的独立集)，我们进行迭代调整：
 * 1. 初始化 $nums' = nums$. Cost = 0.
 * 2. While changes occur:
 *    For every $i \in S$:
 *        Required\_i = $\max(nums'[i-1], nums'[i+1]) + 1$.
 *        If $nums'[i] < \text{Required\_i}$:
 *            Increase $nums'[i]$ to $\text{Required\_i}$.
 *            Cost += $\text{Required\_i} - nums'[i]_{\text{old}}$.
 *    For every $j \notin S$ ($1 \le j \le N-2$):
 *        // 确保 $j$ 不是峰值，即 $\neg (nums'[j] > nums'[j-1] \land nums'[j] > nums'[j+1])$
 *        // 保持 $nums'[j]$ 不变，除非它被 $i \in S$ 的调整所影响。
 *        // 如果 $nums'[j]$ 已经是峰值，我们需要增加邻居的值，但这会增加 $i \in S$ 的成本。
 *        // 这是一个循环依赖，非常复杂。
 * 
 * 最终结论：对于本题的结构，最优解的峰值集 $S$ 必须是满足特定交错模式的独立集，并且由于我们只增加值，我们只需要考虑两种最主要的交错模式：奇数下标或偶数下标。
 * 
 * 我们计算两种最大可能峰值数量的成本，并取最小者。
 * 
 * **模式 1: 峰值在所有奇数下标 $S_{odd} = \{i \mid 1 \le i \le N-2, i \text{ is odd}\}$**
 * **模式 2: 峰值在所有偶数下标 $S_{even} = \{i \mid 1 \le i \le N-2, i \text{ is even}\}$**
 * 
 * 我们需要一个函数 `calculate_cost(S, nums)` 来计算给定峰值集合 $S$ 的最小成本。
 */

typedef long long LL;

/**
 * @brief 计算给定峰值集合 S 的最小操作成本。
 * 
 * 由于操作的连锁反应，我们需要一个迭代过程来稳定数组的值。
 * @param nums 原始数组
 * @param S 目标峰值下标集合
 * @return 最小操作成本
 */
LL calculate_cost(const vector<LL>& nums, const vector<int>& S) {
    int n = nums.size();
    vector<LL> current_nums = nums;
    LL total_cost = 0;
    bool changed = true;

    // 迭代直到所有峰值条件稳定，或者达到最大迭代次数（安全退出）
    // 理论上，由于每次调整都增加值，且目标是满足不等式，它应该收敛。
    // 考虑到 N <= 10^5, 迭代次数可能需要控制。
    // 因为我们只增加值，并且最大值不会无限增长（如果邻居值是固定的），这里我们假设它会收敛。
    // 实际中，迭代次数可能与最大值增长的幅度有关。

    // 限制迭代次数以防死循环，虽然在理论上不应该发生。
    const int MAX_ITER = n * 2 + 5; 
    int iteration = 0;

    while (changed && iteration < MAX_ITER) {
        changed = false;
        iteration++;

        // 1. 确保所有 i in S 都是峰值
        for (int i : S) {
            // i 必须是峰值，即 current_nums[i] > current_nums[i-1] 且 current_nums[i] > current_nums[i+1]

            LL required_left = current_nums[i-1] + 1;
            LL required_right = current_nums[i+1] + 1;
            LL required_i = max(required_left, required_right);

            if (current_nums[i] < required_i) {
                LL diff = required_i - current_nums[i];
                total_cost += diff;
                current_nums[i] += diff;
                changed = true;
            }
        }

        // 2. 确保所有 j not in S (且 1 <= j <= n-2) 不是峰值
        // 如果 j 已经是峰值，且它不是目标峰值，那么我们必须改变 j 的邻居，这会影响到 S 上的元素，形成循环依赖。
        // 
        // 鉴于问题的性质（最大化数量，最小化成本），我们假设最优解是只在 S 上操作，并且不让其他点成为峰值。
        // 只有当某个 j 成为峰值时，我们才需要进行额外操作来“破坏”这个峰值，但这需要减小值，而我们只能增加值。
        // 
        // 因此，我们必须接受：如果仅通过操作 S 上的元素，其他元素 j 意外地成为了峰值，我们不能在当前模型下解决。
        // 但在最优解中，我们预期不会发生这种情况，或者如果发生了，其成本增加小于我们预期的收益。
        // 
        // 经验上，对于此类问题，如果只强制 S 上的元素满足条件，并且不干预非 S 上的元素，通常是正确的路径。
        // 我们只检查 S 上的元素是否满足条件，因为这是我们目标函数的定义。

        // 检查非 S 元素是否意外成为峰值（仅用于调试/验证，不计入成本，因为我们不能“消除”峰值）
        // for (int j = 1; j < n - 1; ++j) {
        //     if (S.end() == find(S.begin(), S.end(), j)) { // j is NOT in S
        //         if (current_nums[j] > current_nums[j-1] && current_nums[j] > current_nums[j+1]) {
        //             // j became a peak unexpectedly. This violates the assumed structure.
        //             // Since we cannot decrease values, this means the cost to prevent this peak is infinite 
        //             // under the simple model, or requires a much more complex DP.
        //             // For competitive programming constraints, we rely on the assumption that enforcing S is enough.
        //         }
        //     }
        // }
    }

    return total_cost;
}

void solve_impl(vector<LL>& nums, LL& result) {
    int n = nums.size();
    if (n < 3) {
        result = 0;
        return;
    }

